// ListView_sethour 点击回调函数 (设置小时)
static void on_hour_list_click(int itemId) {
    // itemId 对应 0-23
    printf("[Alarm] Hour list item clicked: %d\n", itemId);
    
    if (current_time.length() >= 5) {
        // 格式化新的小时部分
        char new_hour_str[3];
        snprintf(new_hour_str, sizeof(new_hour_str), "%02d", itemId);
        // 替换原时间字符串的小时部分
        current_time = std::string(new_hour_str) + current_time.substr(2);
        
        printf("[Alarm] New time after hour change: %s\n", current_time.c_str());
        // 更新UI显示
        update_time_display();
    }
}

// ListView_setmin 点击回调函数 (设置分钟)
static void on_minute_list_click(int itemId) {
    // itemId 对应 0-59
    printf("[Alarm] Minute list item clicked: %d\n", itemId);
    
    if (current_time.length() >= 5) {
        // 格式化新的分钟部分
        char new_min_str[3];
        snprintf(new_min_str, sizeof(new_min_str), "%02d", itemId);
        // 替换原时间字符串的分钟部分
        current_time = current_time.substr(0, 3) + std::string(new_min_str);
        
        printf("[Alarm] New time after minute change: %s\n", current_time.c_str());
        // 更新UI显示
        update_time_display();
    }
}


