static void goldie_app_run(void)
{
    // 获取闹钟服务
    AlarmService* service = get_alarm_service();
    if (service == NULL) {
        printf("[Alarm] Alarm service not available, UI may not work properly\n");
    } else {
        // 初始化服务
        service->init();
        // 从服务加载闹钟列表
        load_alarms_from_service();
    }
    
    main_ui_init();
    
    // 初始化ListView显示 - 显示从服务加载的闹钟列表
    update_listview_display();
    
    // 为添加闹钟按钮设置点击事件
    ButtonView_add_clock->setOnClick(on_add_clock_click);
    
    // // 为时间调整按钮设置点击事件
    // ButtonView_add_1->setOnClick(on_add_1_click);
    // ButtonView_dec_1->setOnClick(on_dec_1_click);
    // ButtonView_add_2->setOnClick(on_add_2_click);
    // ButtonView_dec_2->setOnClick(on_dec_2_click);
    
    // 为开关按钮设置点击事件
    if (ImgButtonView_set_switch) {
        ImgButtonView_set_switch->setOnClick(on_switch_click);
    }
    
    // 为星期选择复选框设置点击事件
    CheckboxView_1->setOnClick(on_weekday_click);
    CheckboxView_2->setOnClick(on_weekday_click);
    CheckboxView_3->setOnClick(on_weekday_click);
    CheckboxView_4->setOnClick(on_weekday_click);
    CheckboxView_5->setOnClick(on_weekday_click);
    CheckboxView_6->setOnClick(on_weekday_click);
    CheckboxView_7->setOnClick(on_weekday_click);
    
    // 为删除闹钟按钮设置点击事件（从列表中移除闹钟）
    if (ButtonView_delete) {
        ButtonView_delete->setOnClick(on_delete_click);
    }
    

    
    // 为设置界面返回按钮设置点击事件
    if (ButtonView_set_back) {
        ButtonView_set_back->setOnClick(on_set_back_click);
    }
    
    // 为ListView设置item点击回调
    if (ListView_clock) {
        ListView_clock->setOnItemClick(on_listview_item_click);
    }

    // 为闹钟设置界面的小时和分钟列表添加点击回调
    if (ListView_sethour) {
        ListView_sethour->setOnItemClick(on_hour_list_click);
    }
    
    if (ListView_setmin) {
        ListView_setmin->setOnItemClick(on_minute_list_click);
    }

    // 检查是否有活跃闹钟（闹钟正在响铃），有则直接跳转到对应的设置界面
    if (service != NULL) {
        int mindex = service->get_actived_alarm();
        if (mindex >= 0) {
            on_listview_item_click(mindex);
        }
    }
    
    printf("[Alarm] All callbacks registered, %zu alarms displayed\n", alarm_list_for_display.size());
}

static void goldie_app_suspend(void)
{
    window_suspend();
}

static void goldie_app_resume(void)
{
    window_resume();
     // 检查是否有活跃闹钟（闹钟正在响铃），有则直接跳转到对应的设置界面
    AlarmService* service = get_alarm_service();
    if (service != NULL) {
        load_alarms_from_service();
        update_listview_display();
        
        int mindex = service->get_actived_alarm();
        if (mindex >= 0) {
            on_listview_item_click(mindex);
        }
    }
}

static void goldie_app_exit(void)
{
    // 注意：闹钟数据由服务管理，不需要应用保存
    window_exit();
}

static void goldie_keyboard_event(int pressure, int key);

static App_t alarm = {
    "闹钟",       // app_name char*
    goldie_app_run,       // h_app_run
    goldie_app_exit,      // h_app_exit
    goldie_app_suspend,   // h_app_suspend
    goldie_app_resume,    // h_app_resume
    goldie_touch_event,   // h_touch_event
    goldie_keyboard_event,// h_keyboard_event
    (uint16_t*)rgb16_clock_56_56,             
};

// 返回按钮回调函数 - 返回到上一级界面
static void on_back_click(void*) {
    goldie_exit_app(&alarm);
	if(alarm_service){
		alarm_service->cancel_alarm();
	}
}

static void goldie_keyboard_event(int pressure, int key)
{
    if((key == SYSTEM_KEY_VALUE_BACK) && (pressure == 1))
    {
    	printf("goldie_keyboard_event %p \r\n",FrameView_set);
    	if(FrameView_set&&FrameView_set->isVisible())
    	{
		on_set_back_click(NULL);
	}else{
        		goldie_exit_app(&alarm);
		if(alarm_service){
			alarm_service->cancel_alarm();
		}
	}
    }
}

static void test_entry(void)
{
    install_app(&alarm);
}

GOLDIE_INIT_CALL_(test_entry);
